# 解析响应并保存图片

根据你的代码，响应中的图片数据通常以 base64 编码格式返回。以下是完整的修改代码：

```python
import requests
import json
import base64

url = "http://35.220.164.252:3888/v1beta/models/gemini-3-pro-image-preview:generateContent/"

payload = json.dumps({
    "contents": [
        {
            "role": "user",
            "parts": [
                {
                    "text": "draw a cat"
                }
            ]
        }
    ],
    "generationConfig": {
        "responseModalities": [
            "TEXT",
            "IMAGE"
        ],
        "imageConfig": {
            "aspectRatio": "16:9",
            "imageSize": "4K"
        }
    }
})

headers = {
    'Authorization': 'Bearer sk-38Ioe69LZLL8mOQzKpdg1rG94hWSXRIeAARVjMJNBhRFMFlM',
    'Content-Type': 'application/json'
}

response = requests.request("POST", url, headers=headers, data=payload)

# 解析响应
response_data = response.json()
print("完整响应：", json.dumps(response_data, indent=2))

# 提取图片数据并保存
try:
    # 遍历响应中的内容
    for candidate in response_data.get('candidates', []):
        for part in candidate.get('content', {}).get('parts', []):
            # 查找包含图片数据的部分
            if 'inlineData' in part:
                # 获取base64编码的图片数据
                image_data = part['inlineData']['data']
                mime_type = part['inlineData']['mimeType']

                # 根据MIME类型确定文件扩展名
                extension = mime_type.split('/')[-1]
                filename = f"generated_image.{extension}"

                # 解码并保存图片
                image_bytes = base64.b64decode(image_data)
                with open(filename, 'wb') as f:
                    f.write(image_bytes)

                print(f"图片已保存为: {filename}")

            # 如果有文本内容也打印出来
            elif 'text' in part:
                print(f"文本内容: {part['text']}")

except Exception as e:
    print(f"保存图片时出错: {e}")
    print("响应内容:", response.text)
```

## 可能的响应格式

响应可能是以下几种格式之一：

### 格式1：inlineData
```json
{
  "candidates": [{
    "content": {
      "parts": [{
        "inlineData": {
          "mimeType": "image/png",
          "data": "base64编码的图片数据..."
        }
      }]
    }
  }]
}
```

### 格式2：直接返回URL
```python
# 如果返回的是图片URL
if 'imageUrl' in part or 'url' in part:
    image_url = part.get('imageUrl') or part.get('url')
    img_response = requests.get(image_url)
    with open('generated_image.png', 'wb') as f:
        f.write(img_response.content)
```

